export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "濃霧中,李杰抱著受傷的女孩,清水恵美緊跟在旁,三人艱難地穿過森林。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沉重的呼吸聲和腳步聲是唯一的聲響。李杰的手臂開始發酸,但他咬緊牙關,一步一步地往前走。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "懷中的女孩雖然輕,但長時間抱著,加上要小心避開箭傷,讓他的體力消耗很快。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(喘著氣,試圖分散注意力)妳...叫什麼名字?我們總不能一直叫妳「那個女孩」吧。" },
    { characterId: CharacterId.TakahashiMisaki, character: "多話女大生", dialogue: "(虛弱地,聲音很小)高橋...美咲...東京人...早稻田大學...二年級..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(溫和地)美咲,撐住。我們會找到地方的。妳已經很勇敢了,再堅持一下。" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(微弱地點頭,沒有多餘的力氣說話)嗯...謝謝..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三人沉默地前行。霧氣越來越濃,幾乎無法辨識方向。李杰只能憑著感覺,盡量保持直線前進。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "時間變得模糊,在這片永恆的霧氣中,他不知道走了多久。可能是二十分鐘,也可能是一個小時。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(擔心地)李杰先生...您還撐得住嗎?要不要我幫忙...雖然我力氣很小..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(勉強笑了笑)我沒事。妳幫我看著前面的路就好,別讓我撞到樹。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又走了不知多久,李杰的雙臂已經開始發抖。就在他考慮是否該停下來休息時——" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "前方的霧氣中隱約出現了一個方正的輪廓。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(驚喜地,聲音帶著難以置信)李杰先生!那是...那是房子!真的是房子!" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是一棟木造房屋,在濃霧中顯得格外真實。不是幻影,不是錯覺,而是實實在在的建築。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房子看起來保養得相當不錯。木牆完整,屋頂也沒有破損,甚至還有一個小小的煙囪。窗戶雖然關著,但玻璃完好無損。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最重要的是——這裡看起來像是有人居住或至少定期維護的痕跡。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(謹慎地)小心點,先確認一下有沒有人。如果有人住在這裡,我們要先禮貌地詢問能不能借用。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美點點頭,快步走到門前。她深吸一口氣,輕輕敲了敲門。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(用日語)不好意思...請問有人在嗎?我們遇到了一些麻煩..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有回應。她又敲了幾次,依然沒有任何動靜。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(小聲對李杰說)好像沒有人..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "試試看門有沒有鎖。如果沒鎖,我們先進去。這是緊急情況。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美輕輕推了推門把。門沒有上鎖,發出輕微的吱呀聲緩緩打開。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她探頭往裡看,屏住呼吸觀察了幾秒,然後回頭向李杰點頭示意安全。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(確認後)沒有人...而且看起來很久沒人住了。但是很乾淨,不像廢棄的房子。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰抱著美咲走進屋內。清水恵美關上門,隔絕了外面的寒冷和霧氣。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房子內部出乎意料地整潔。靠牆有一張簡單的單人床,床單雖然有些灰塵但還算乾淨。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "旁邊是一張木桌和幾把椅子。角落裡有個小廚房,配備著簡陋但實用的爐灶和櫥櫃。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "另一側還有一個用木板隔開的小空間,推開門一看,是個簡易的廁所。麻雀雖小,五臟俱全。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(環顧四周,警覺地)這個地方...太乾淨了。不像是廢棄的房子,更像是有人定期打掃維護。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "恵美,幫我把床上的東西清一下。我們先把她安置好,然後要小心行事。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美迅速將床上積了一層灰的毯子抖開,用力拍打幾下,然後重新鋪平。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰小心翼翼地將美咲放在床上,讓她平躺。他輕輕放下她的雙腿,避免碰到箭傷。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "美咲發出一聲痛苦的呻吟,眉頭緊皺,但隨即安靜下來,似乎已經虛弱到沒有力氣喊痛。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(開始翻找櫥櫃,語氣帶著希望)我...我找找看有沒有什麼可以用的...說不定有繃帶或藥品..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美在廚房的櫥櫃裡仔細翻找著。第一個櫥櫃裡是一些碗盤和餐具,第二個是乾糧。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在她打開第三個櫥櫃時,眼睛亮了起來。她找到了一些乾淨的布條、一個裝著清水的陶罐,以及一個精緻的小木盒。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "打開木盒,裡面整齊地擺放著各種瓶瓶罐罐和小工具。有鑷子、剪刀、縫合針,還有幾瓶標著奇怪符號的藥瓶。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(驚喜地)李杰先生!這裡有急救用的東西!而且看起來很專業!" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她又在櫥櫃深處摸到了一本薄薄的冊子。封面用古老的字體寫著「森林傷患處理指南」。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻開一看,裡面詳細記載著如何使用房子裡儲存的精靈草藥來處理各種傷口。每一頁都配有插圖和詳細說明。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(驚訝又困惑)這...這本書...好像就是為了這種情況準備的...但是為什麼會有這種東西?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(翻開書頁,皺著眉)可是...上面的字...我看不懂...這些字好奇怪...李杰先生,你能看懂嗎?" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(接過冊子,快速翻閱,有些驚訝)咦...我看得懂耶。雖然字體有點古老,但意思很清楚。太好了,按照上面的方法來處理傷口。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人按照指南的指示開始處理美咲的傷口。李杰用清水仔細清洗手臂上的劍傷,洗掉凝固的血跡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美找到指南中提到的淡綠色藥膏,小心翼翼地塗抹在傷口上。藥膏散發著清涼的草藥香氣。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "至於大腿上的箭,李杰深吸一口氣。這是最困難的部分。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(嚴肅地對美咲說)美咲,接下來會很痛。妳咬著這個,盡量忍耐一下。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他將一塊布條遞給美咲。美咲虛弱地咬住布條,眼中充滿恐懼,但她點了點頭。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰按照書上的步驟,先在箭的周圍塗上麻醉藥膏,等待幾分鐘讓它生效。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後,他一手穩住美咲的大腿,另一手握住箭桿,深吸一口氣,用力但穩定地將箭拔了出來。" },
    { characterId: CharacterId.TakahashiMisaki, character: "高橋美咲", dialogue: "(痛得幾乎暈厥,發出悶哼聲,眼淚順著臉頰流下)嗚..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰迅速用布條按壓止血,然後塗上藥膏,最後用繃帶仔細包紮。整個過程不到兩分鐘,但感覺像過了一個世紀。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "處理完畢後,美咲虛弱地睡了過去,呼吸變得平緩。疼痛和失血讓她的身體進入了保護性的昏睡。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(擦了擦額頭的汗,長舒一口氣)暫時處理好了。讓她好好休息吧。只要傷口不感染,應該能撐過去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美為美咲蓋上毯子,小心地將毯子塞好,確保她能安穩地睡著。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人都鬆了一口氣。處理傷口的緊張感消退後,疲憊和飢餓感突然湧了上來。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(小聲地,有些不好意思)李杰先生...我們...要不要吃點東西?我...我肚子有點餓了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(苦笑)我也是。剛才太緊張沒注意,現在放鬆下來才發現自己餓得不行。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰這才發現自己從派對結束後就沒吃過東西。兩人走到廚房,在櫥櫃裡仔細搜索。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們找到了一些保存良好的乾糧、醃菜,以及一小袋看起來很新鮮的米。甚至還有一些乾燥的蔬菜和香菇。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(看著這些食材)這些東西...看起來不像是放了很久的樣子...這個房子真的很奇怪..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "先填飽肚子再說。妳會煮飯嗎?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(點頭)我...我試試看..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "清水恵美熟練地檢查爐灶,發現裡面還有乾燥的木柴。她用火柴點燃火,開始煮一鍋簡單的粥。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她在粥裡加了一些乾燥蔬菜和香菇,還放了一點點鹽。很快,溫暖的香氣就在小屋裡飄散開來。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人圍坐在木桌旁,安靜地吃著。熱粥的溫暖讓疲憊的身體得到了一絲慰藉。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(真誠地)妳的廚藝不錯。在這種情況下還能煮出這麼好吃的粥,不簡單。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(臉微紅,小聲地)謝謝...我...我一個人住的時候...常常自己煮...所以習慣了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "一個人住?妳父母不在東京嗎?" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(低頭看著碗)嗯...父母在福岡...我來東京上大學...一個人租了個小公寓..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "剛開始很不習慣...但慢慢就學會照顧自己了...煮飯、打掃..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(理解地點頭)一個人生活確實需要學很多東西。我剛來日本的時候也是,什麼都要自己來。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人簡短地聊了幾句,都太疲憊了,沒有多餘的精力深談。吃完飯後,清水恵美找到了另外兩條毯子。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "毯子雖然有些舊,但很乾淨,還帶著一股淡淡的薰衣草香氣。她將毯子鋪在地板上。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(站起身)妳睡床吧,我睡地板就好。妳照顧了美咲那麼久,也累了。" },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "(堅定地搖頭)不行...美咲需要床...她的傷勢比我們嚴重多了。我...我和你一起睡地板就好..." },
    { characterId: CharacterId.ShimizuEmi, character: "清水恵美", dialogue: "而且地板也不算太硬...有毯子墊著應該沒問題..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "(看著她堅定的眼神,沒有再堅持)好吧。那我們都早點休息。不知道明天會發生什麼事。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩人各自裹著毯子,並排躺在地板上,中間保持著適當的距離。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "疲憊讓他們很快就進入了夢鄉。屋外,濃霧依然籠罩著森林,但至少這一晚,他們有了一個安全的庇護所。" },
];
